import React, { useState, useEffect, useRef } from 'react'
import { useHistory, Link } from 'react-router-dom'
import axios from 'axios'
import {
  CButton,
  CCard,
  CCardBody,
  CCardGroup,
  CCol,
  CContainer,
  CForm,
  CFormInput,
  CInputGroup,
  CInputGroupText,
  CRow,
  CModal,
  CModalBody,
  CModalFooter,
  CModalTitle,
  CModalHeader,
  CBadge,
  CToaster,
  CSpinner,
  CCallout,
} from '@coreui/react'
import CIcon from '@coreui/icons-react'
import { cilLockLocked, cilUser, cibGmail, cilPhone } from '@coreui/icons'
import { setUserSession } from '../../../utils/Auth'
import logo from '../../../assets/brand/logo.png'
import Notify from 'src/utils/Notify'

const Login = () => {
  const [validated, setValidated] = useState(false)
  const [loginDetails, setloginDetails] = useState({
    matric: '',
    password: '',
  })
  const [forgotPass, setForgotPass] = useState({
    email: '',
  })
  const [registerForm, setRegisterForm] = useState({
    matric: '',
    email: '',
    phone: '',
  })
  const [message, setMessage] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(false)
  const [toast, addToast] = useState(0)
  const [visible, setVisible] = useState(true)
  const [create, setCreate] = useState(false)
  const [forgot, setForgot] = useState(false)
  const toaster = useRef()

  useEffect(() => {
    if (message) addToast(notify)
  }, [message])

  const notify = <Notify error={error} message={message} />

  const history = useHistory()

  const handleLoginChange = (e) => {
    const { id, value } = e.target
    setloginDetails((prevState) => ({
      ...prevState,
      [id]: value,
    }))
  }

  const handleRegChange = (e) => {
    const { id, value } = e.target
    setRegisterForm((prevState) => ({
      ...prevState,
      [id]: value,
    }))
  }

  const handleForgotPassChange = (e) => {
    const { id, value } = e.target
    setForgotPass((prevState) => ({
      ...prevState,
      [id]: value,
    }))
  }

  const handleLogin = (e) => {
    e.preventDefault()
    if (!loginDetails.matric || !loginDetails.password) return false
    setMessage(null)
    setLoading(true)
    setError(null)

    axios
      .post('https://records.run.edu.ng/api/app/login', {
        matno: loginDetails.matric,
        password: loginDetails.password,
      })
      .then((res) => {
        console.log(res)
        setLoading(false)
        setUserSession(res.data.token, res.data.applicant, res.data.student)
        setMessage('Login Successful')
        history.push('/dashboard')
      })
      .catch((err) => {
        setLoading(false)
        setError(true)
        if (err.response) {
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleRegister = (event) => {
    event.preventDefault()
    setMessage(null)
    setError(false)
    const form = event.currentTarget
    if (form.checkValidity() === false) {
      event.stopPropagation()
      return
    }
    setValidated(true)
    axios
      .post('https://records.run.edu.ng/api/app/register', {
        matno: registerForm.matric,
        email: registerForm.email,
        phone: registerForm.phone,
      })
      .then((res) => {
        setError(false)
        setMessage(res.data.message)
        setValidated(false)
      })
      .catch((err) => {
        setError(true)
        setValidated(false)
        if (err.response) {
          console.log(err.response)
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }

  const handleForgotPass = (e) => {
    setMessage(null)
    setError(false)
    const form = e.currentTarget
    if (form.checkValidity() === false) {
      e.stopPropagation()
      return
    }
    setValidated(true)
    axios
      .post('https://records.run.edu.ng/api/app/forgot_password', {
        email: forgotPass.email,
      })
      .then((res) => {
        setError(false)
        setMessage(res.data.message)
        setValidated(false)
      })
      .catch((err) => {
        setError(true)
        setValidated(false)
        if (err.response) {
          console.log(err.response)
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }
  return (
    <div className="bg-light min-vh-100 d-flex flex-row align-items-center">
      <CContainer>
        <CRow className="justify-content-center">
          <CCol md={8}>
            <CCardGroup>
              <CCard className="p-4">
                <CCardBody>
                  <CForm>
                    <img
                      style={{ width: '100%' }}
                      className="text-align:center"
                      src={logo}
                      alt="logo"
                    />
                    <h2 className="text-center">
                      <CBadge color="primary" shape="rounded-pill">
                        Transcript Portal
                      </CBadge>
                    </h2>

                    <p className="text-medium-emphasis">Sign In to your account</p>
                    <CInputGroup className="mb-3">
                      <CInputGroupText>
                        <CIcon icon={cilUser} />
                      </CInputGroupText>
                      <CFormInput
                        type="text"
                        id="matric"
                        placeholder="Matric number"
                        onChange={handleLoginChange}
                      />
                    </CInputGroup>
                    <CInputGroup className="mb-4">
                      <CInputGroupText>
                        <CIcon icon={cilLockLocked} />
                      </CInputGroupText>
                      <CFormInput
                        id="password"
                        type="password"
                        placeholder="Password"
                        onChange={handleLoginChange}
                      />
                    </CInputGroup>
                    <CRow className="justify-content-center">
                      <CCol xs="auto">
                        <CButton
                          color="primary"
                          className="px-4"
                          onClick={handleLogin}
                          type="submit"
                          disabled={loading}
                        >
                          {loading && (
                            <CSpinner
                              component="span"
                              size="sm"
                              color="light"
                              variant="grow"
                              aria-hidden="true"
                            />
                          )}
                          Login
                        </CButton>
                      </CCol>
                    </CRow>
                    <CRow className="d-flex">
                      <CCol xs="auto" className="me-auto">
                        <Link to="#" onClick={() => setCreate(!create)}>
                          New User?
                        </Link>
                      </CCol>
                      <CCol xs="auto">
                        <Link to="#" onClick={() => setForgot(!forgot)}>
                          Forgot Password?
                        </Link>
                      </CCol>
                    </CRow>
                  </CForm>
                </CCardBody>
              </CCard>
            </CCardGroup>
          </CCol>
        </CRow>
      </CContainer>

      <CToaster ref={toaster} push={toast} placement="top-end" />
      <CModal visible={visible} onClose={() => setVisible(false)}>
        <CModalHeader onClose={() => setVisible(false)}>
          <CModalTitle>Welcome</CModalTitle>
        </CModalHeader>
        <CModalBody>
          Please read below details
          <CCallout color="primary">
            Click on `New User` to create your account using your Matric number and current email
            address (A default password will be sent to you)
          </CCallout>
          <CCallout color="success">
            Forgot your matric number? We can help you retrieve it by filling the required details
          </CCallout>
        </CModalBody>
        <CModalFooter>
          <CButton color="secondary" onClick={() => setVisible(false)}>
            Close
          </CButton>
        </CModalFooter>
      </CModal>

      <CModal visible={create} onClose={() => setCreate(false)}>
        <CForm noValidate validated={validated} onSubmit={handleRegister}>
          <CModalHeader onClose={() => setCreate(false)}>
            <CModalTitle>Create New Account</CModalTitle>
          </CModalHeader>
          <CModalBody>
            <CInputGroup className="mb-3">
              <CInputGroupText>
                <CIcon icon={cilUser} />
              </CInputGroupText>
              <CFormInput
                id="matric"
                placeholder="Enter your matric number"
                onChange={handleRegChange}
                required
              />
            </CInputGroup>
            <CInputGroup className="mb-3">
              <CInputGroupText>
                <CIcon icon={cibGmail} />
              </CInputGroupText>
              <CFormInput
                type="email"
                id="email"
                placeholder="Enter your email address"
                onChange={handleRegChange}
                required
              />
            </CInputGroup>
            <CInputGroup className="mb-3">
              <CInputGroupText>
                <CIcon icon={cilPhone} />
              </CInputGroupText>
              <CFormInput
                type="text"
                id="phone"
                placeholder="Enter your phone number"
                onChange={handleRegChange}
                required
              />
            </CInputGroup>
            <Link to="/forgot">
              <h6>Forgot matric number?</h6>
            </Link>
          </CModalBody>
          <CModalFooter>
            <CButton color="secondary" onClick={() => setCreate(false)}>
              Close
            </CButton>
            <CButton disabled={validated} type="submit" color="primary">
              {validated && (
                <CSpinner
                  component="span"
                  size="sm"
                  color="light"
                  variant="grow"
                  aria-hidden="true"
                />
              )}
              Submit
            </CButton>
          </CModalFooter>
        </CForm>
      </CModal>

      <CModal visible={forgot} onClose={() => setForgot(false)}>
        <CForm noValidate validated={validated} onSubmit={handleForgotPass}>
          <CModalHeader onClose={() => setForgot(false)}>
            <CModalTitle>Forgot Password</CModalTitle>
          </CModalHeader>
          <CModalBody>
            <CInputGroup className="mb-3">
              <CInputGroupText>
                <CIcon icon={cibGmail} />
              </CInputGroupText>
              <CFormInput
                id="email"
                onChange={handleForgotPassChange}
                placeholder="Enter your email address"
                required
              />
            </CInputGroup>
          </CModalBody>
          <CModalFooter>
            <CButton color="secondary" onClick={() => setForgot(false)}>
              Close
            </CButton>
            <CButton disabled={validated} type="submit" color="primary">
              {validated && (
                <CSpinner
                  component="span"
                  size="sm"
                  color="light"
                  variant="grow"
                  aria-hidden="true"
                />
              )}
              Send
            </CButton>
          </CModalFooter>
        </CForm>
      </CModal>
    </div>
  )
}

export default Login
